def is_valid_identifier(identifier):
    """Validate that identifier is safe for SQL usage"""
    if not isinstance(identifier, str):
        return False
        
    # Check for empty or overly long identifiers
    if not identifier or len(identifier) > 64:
        return False
        
    # Check for valid characters (alphanumeric, underscore, dot for schema.table)
    import re
    pattern = r'^[a-zA-Z_][a-zA-Z0-9_\.]*$'
    return bool(re.match(pattern, identifier))

